/** CmmtMenuDao.select */
select

from cmmt_menu cm
where
	system_id = #{systemId}
	and menu_id = #{menuId}

/** CmmtMenuDao.selectLastChild */
select

from cmmt_menu cm
where
	system_id = #{systemId}
	and parent_menu_id = #{menuId}
	and sort_order = (select max(sort_order) from cmmt_menu where system_id = #{systemId} and parent_menu_id = #{menuId})

/** CmmtMenuDao.selectAboveMenu */ select
from cmmt_menu a join (select * from cmmt_menu where system_id = #{systemId} and menu_id = #{menuId}) b on (a.system_id = b.system_id and a.parent_menu_id = b.parent_menu_id) where
a.sort_order = (select max(sort_order) from cmmt_menu where system_id = b.system_id AND parent_menu_id = b.parent_menu_id AND sort_order < b.sort_order)

/** CmmtMenuDao.selectBelowMenu */ select
from cmmt_menu a join (select * from cmmt_menu where system_id = #{systemId} and menu_id = #{menuId}) b on (a.system_id = b.system_id and a.parent_menu_id = b.parent_menu_id) where
a.sort_order = (select min(sort_order) from cmmt_menu where system_id = b.system_id AND parent_menu_id = b.parent_menu_id AND sort_order > b.sort_order)

/** CmmtMenuDao.selectList_parentMenuId */
select

from cmmt_menu cm
where
	system_id = #{systemId}
	and parent_menu_id = #{menuId}
order by
	sort_order

/** CmmtMenuDao.selectAll_roleId */
SELECT
, case when (select menu_id from cmmt_menu_role where system_id = #{systemId} and menu_id = m.menu_id and role_id = #{roleId}) is null then false else true end as enabled FROM cmmt_menu_hierarchy m ORDER BY PATH

