mapper.insert:
/** CmmtMenuDao.insert */
insert into cmmt_menu (
	system_id
	,menu_id
	,menu_nm
	,url
	,new_window
	,parent_menu_id
	,sort_order
	,remark
	,creator_id
	,created_dt
	,updater_id
	,updated_dt
) values (
	#{systemId}
	,#{menuId}
	,#{menuNm}
	,#{url}
	,#{newWindow}
	,#{parentMenuId}
	,#{sortOrder}
	,#{remark}
	,#{creatorId}
	,#{createdDt}
	,#{updaterId}
	,#{updatedDt}
)

mapper.update:
/** CmmtMenuDao.incSortOrder */
update cmmt_menu set
	sort_order = sort_order + 1
where
	system_id = #{systemId}
	and parent_menu_id = (SELECT parent_menu_id from cmmt_menu where menu_id = #{menuId})
	and sort_order >= #{sortOrder}

/** CmmtMenuDao.decSortOrder */
update cmmt_menu set
	sort_order = sort_order - 1
where
	system_id = #{systemId}
	and parent_menu_id = (SELECT parent_menu_id from cmmt_menu where menu_id = #{menuId})
	and sort_order >= #{sortOrder}

/** CmmtMenuDao.update */
update cmmt_menu set
	menu_nm         = #{menuNm}
	,url            = #{url}
	,new_window     = #{newWindow}
	,parent_menu_id = #{parentMenuId}
	,sort_order     = #{sortOrder}
	,remark         = #{remark}
	,updater_id     = #{updaterId}
	,updated_dt     = #{updatedDt}
where
	system_id = #{systemId}
	and menu_id = #{menuId}

